		for(int i = 0 ; i < Y ; i++)

			for(int j = 0 ; j < X ; j++){

				char c; scanf(" %c",&c);

				if(c == 'S'){

					sx = j , sy = i;

				}else if( c == 'G'){

					gx = j , gy = i;

				}else if( c != '.'){

					c = c - '1';

					x[c][sz[c]] = j;

					y[c][sz[c]++] = i;			

				}

			}

